int mca_lex(void *yylval_param, struct YYLTYPE *yylloc_param)
{
    (void)yylloc_param;
    if (g_current_token == NULL) {
        return 0; // End of input
    }
    mc_lex_token *token = g_current_token;
    mc_lex_token **yylval = (mc_lex_token**)yylval_param;
    *yylval = token;
    mprintf(MCC_LOG_TOKEN, "[%d|%s|%d..%d] ", token->tid, token->tstring, token->tpos, token->tpos+token->tlen);
    g_current_token = (mc_lex_token*)token->next;
    g_last_token = token;

    return token->tid;
}
